```class Solution {
public:
    bool checkPalindromeFormation(string a, string b) {
        int n = a.size();
        for (int i = 0; i < n; ++i) {
            string aprefix = a.substr(0, i + 1);
            string asuffix = a.substr(i + 1);
            string bprefix = b.substr(0, i + 1);
            string bsuffix = b.substr(i + 1);
            if (isPalindrome(aprefix + bsuffix) || isPalindrome(bprefix + asuffix)) {
                return true;
            }
        }
        return false;
    }

    bool isPalindrome(string s) {
        int l = 0, r = s.size() - 1;
        while (l < r) {
            if (s[l] != s[r]) {
                return false;
            }
            ++l;
            --r;
        }
        return true;
    }
};
